{
  "domain_analysis": {
    "business_context": "A global logistics platform introducing real-time earnings breakdown visibility for drivers. The feature intersects employment law, compensation transparency regulations, and labor classification rules that vary dramatically by jurisdiction. This is not a simple UI feature — it encodes legal obligations, labor relationships, and financial disclosure rules that differ per market.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task, calculated before bonuses, tips, or deductions. For employees (CA), this must meet or exceed minimum wage guarantees. For contractors (Indonesia), this is the agreed task rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded on top of base pay for completing a delivery, potentially influenced by distance, time, surge, or performance metrics." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer directed to the driver. Must never be commingled with or substituted for base pay or bonuses." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings — e.g., equipment fees, insurance contributions, advance repayments, or tax withholdings. The legal permissibility and disclosure requirements for deductions vary by jurisdiction." },
      { "term": "Gross Earnings", "definition": "The sum of base pay + per-delivery bonus + tips, before any deductions are applied." },
      { "term": "Net Earnings", "definition": "Gross earnings minus all deductions. The amount the driver actually receives." },
      { "term": "Driver Classification", "definition": "The legal labor status of the driver — employee or independent contractor — which determines which wage laws, disclosure obligations, and deduction rules apply." },
      { "term": "Earnings Period", "definition": "The time window over which earnings are aggregated for display. Real-time means per-delivery visibility; periodic means per pay cycle." },
      { "term": "Works Council Approval", "definition": "In Germany, the legally required consent from the Betriebsrat before any system that displays or modifies compensation information can be deployed to drivers." },
      { "term": "Itemized Wage Statement", "definition": "In California, a legally mandated document (Labor Code §226) showing gross wages, total hours, deductions, net wages, and pay period — which this feature effectively digitizes." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings display must show all four components separately: base pay, per-delivery bonus, tips, and deductions. No component may be hidden or merged into another.",
      "invariant": true,
      "invariant_justification": "Merging or hiding components would misrepresent driver compensation. In California this violates Labor Code §226; in all jurisdictions it undermines the stated business purpose of transparency.",
      "testable_assertion": "Given any completed delivery, the earnings breakdown API response contains exactly four distinct line items: base_pay, per_delivery_bonus, tips, and deductions, each with an independent numeric value."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be used to offset or subsidize base pay or bonus calculations. Tip amounts must have zero effect on the computation of base pay and per-delivery bonus.",
      "invariant": true,
      "invariant_justification": "Tip credit against base pay is illegal in California for employees. Even where legal, commingling tips with base pay is a fundamental domain integrity violation — tips are customer-directed funds, not employer compensation.",
      "testable_assertion": "Given a delivery where tip = $20, base_pay and per_delivery_bonus must be identical to a delivery with the same parameters where tip = $0."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings display must include: gross wages earned, total hours worked, all deductions with itemized descriptions, net wages, the inclusive dates of the pay period, and the driver's name/ID. This satisfies Labor Code §226 itemized wage statement requirements.",
      "invariant": true,
      "invariant_justification": "California Labor Code §226 mandates specific fields on wage statements. Omitting any field exposes the platform to statutory penalties of up to $4,000 per employee plus actual damages. This is a legal compliance invariant, not a policy preference.",
      "testable_assertion": "Given a California-classified driver, the earnings response includes fields: gross_wages, total_hours_worked, deductions (array with description per item), net_wages, pay_period_start, pay_period_end, and driver_identifier."
    },
    {
      "id": "BR-4",
      "rule": "In Germany, the earnings transparency feature must not be deployed to any driver until works council (Betriebsrat) approval has been obtained and recorded in the system.",
      "invariant": true,
      "invariant_justification": "Under the German Works Constitution Act (BetrVG §87), introducing or modifying systems that monitor or display employee performance/compensation data requires works council co-determination. Deploying without approval is illegal and can result in injunctions halting the feature entirely.",
      "testable_assertion": "Given a German jurisdiction, the feature flag for earnings transparency returns disabled unless a works_council_approval record exists with status=approved and an approval_date on or before the current date."
    },
    {
      "id": "BR-5",
      "rule": "Each deduction must be individually itemized with a human-readable description and amount. Deductions must never be displayed as a single aggregate number.",
      "invariant": true,
      "invariant_justification": "An aggregate deduction number hides what is being deducted and why. In California this violates §226 itemization requirements. Across all jurisdictions, a lump-sum deduction defeats the transparency purpose and creates dispute risk.",
      "testable_assertion": "Given a delivery with multiple deductions, the deductions field is an array where each element contains a description (string, non-empty) and an amount (numeric), and no element is labeled 'total' or 'other' without further breakdown."
    },
    {
      "id": "BR-6",
      "rule": "Driver classification (employee vs. independent contractor) must be determined by jurisdiction and must govern which earnings rules, disclosure fields, and deduction policies apply.",
      "invariant": true,
      "invariant_justification": "Applying employee wage rules to contractors (or vice versa) creates legal liability. In California, misclassification under AB5 carries penalties. The classification is a structural invariant that gates all downstream compensation logic.",
      "testable_assertion": "Given a driver in California, their classification is 'employee'. Given a driver in Indonesia, their classification is 'independent_contractor'. The classification field is never null and is derived from jurisdiction, not user input."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must be available in real time, defined as within 60 seconds of delivery completion for per-delivery views.",
      "invariant": false,
      "invariant_justification": "The 60-second SLA is a business policy for user experience, not a legal or data integrity constraint. It could be relaxed to 5 minutes without violating any law or corrupting data.",
      "testable_assertion": "Given a delivery marked as completed at time T, the earnings breakdown for that delivery is queryable by the driver by T+60s."
    },
    {
      "id": "BR-8",
      "rule": "In California, if a driver's effective hourly rate (gross earnings / hours worked) falls below the applicable minimum wage for any pay period, the system must flag this for immediate review and adjustment.",
      "invariant": true,
      "invariant_justification": "Under AB5, California drivers are employees entitled to minimum wage. Displaying earnings that reveal sub-minimum-wage pay without flagging it creates documented evidence of a wage violation. The system cannot be complicit in showing illegal pay without action.",
      "testable_assertion": "Given a California driver whose gross_earnings / total_hours_worked < state_minimum_wage for a pay period, a minimum_wage_violation_flag is set to true and an alert is generated for the compensation team."
    },
    {
      "id": "BR-9",
      "rule": "All monetary values must be displayed in the local currency of the driver's operating jurisdiction, using locale-appropriate formatting.",
      "invariant": true,
      "invariant_justification": "Displaying USD to a driver in Indonesia, or using wrong decimal separators, creates material confusion about actual pay. Currency and locale are tied to jurisdiction and are not cosmetic preferences.",
      "testable_assertion": "Given a driver in Germany, all earnings values are in EUR with comma decimal separator. Given Indonesia, values are in IDR. Given California, values are in USD."
    },
    {
      "id": "BR-10",
      "rule": "Earnings data is private to the individual driver. No driver may view another driver's earnings breakdown.",
      "invariant": true,
      "invariant_justification": "Compensation data is personally identifiable financial information. Cross-driver visibility would violate GDPR (Germany), California privacy law, and basic data integrity.",
      "testable_assertion": "Given driver A requesting earnings for driver B (where A ≠ B), the system returns 403 Forbidden and logs an unauthorized access attempt."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown within 60 seconds",
      "then": "They see base pay, per-delivery bonus, tips, itemized deductions, gross wages, net wages, total hours worked, and pay period dates — all in USD"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany where works council approval has NOT been granted",
      "when": "They attempt to access the earnings transparency feature",
      "then": "The feature is unavailable and they see a message explaining it is pending approval — no earnings breakdown is shown"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany where works council approval HAS been granted",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and itemized deductions in EUR with locale-appropriate formatting"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and itemized deductions in IDR — no hours-worked or pay-period fields are required (contractor classification)"
    },
    {
      "id": "AC-5",
      "given": "A California driver whose computed hourly rate is below the state minimum wage for a pay period",
      "when": "The earnings for that period are calculated",
      "then": "The system flags the violation, alerts the compensation team, and the driver's display includes a notice that an adjustment is being reviewed"
    },
    {
      "id": "AC-6",
      "given": "A customer leaves a $15 tip on a delivery",
      "when": "The driver's base pay and bonus are calculated",
      "then": "The tip has zero influence on those calculations — base pay and bonus amounts are identical to a no-tip scenario with the same delivery parameters"
    },
    {
      "id": "AC-7",
      "given": "A driver has three deductions: insurance ($5), equipment rental ($3), advance repayment ($10)",
      "when": "They view their earnings breakdown",
      "then": "They see three separate line items with descriptions and amounts — not a single '$18 deductions' line"
    },
    {
      "id": "AC-8",
      "given": "Driver A is authenticated",
      "when": "Driver A attempts to access Driver B's earnings data via API",
      "then": "The request is rejected with 403 and an unauthorized access event is logged"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A delivery is completed but the tip is added by the customer 30 minutes later",
      "expected_behavior": "The initial earnings breakdown shows tip as $0.00. When the tip is added, the breakdown updates to reflect it. Base pay and bonus must NOT be recalculated. The system must handle eventual tip arrival without retroactively altering non-tip components."
    },
    {
      "scenario": "A driver operates across jurisdictions (e.g., lives in Germany but completes a delivery across the Dutch border)",
      "expected_behavior": "The jurisdiction — and therefore classification, currency, and disclosure rules — must be determined by the operating jurisdiction of the delivery, not the driver's home address. The system must have a clear jurisdiction-resolution rule per delivery."
    },
    {
      "scenario": "Germany works council approval is revoked after initial rollout",
      "expected_behavior": "The feature must be immediately disabled for all German drivers. Historical earnings data access should follow the revocation terms negotiated with the works council. The system must support approval revocation, not just initial approval."
    },
    {
      "scenario": "A delivery has zero deductions",
      "expected_behavior": "The deductions section displays as an empty list or a clear 'No deductions' indicator — not as a hidden/missing section. The driver should never wonder whether deductions were applied but not shown."
    },
    {
      "scenario": "California minimum wage changes mid-pay-period",
      "expected_behavior": "Hours worked before the change are evaluated against the old minimum wage; hours after the change against the new rate. The system must support effective-dated minimum wage configurations, not a single global value."
    },
    {
      "scenario": "A delivery is disputed or cancelled after earnings are displayed",
      "expected_behavior": "The earnings breakdown must update to reflect the reversal with a clear adjustment line item visible to the driver. Earnings must never silently disappear — every change to previously-displayed earnings must be auditable and explained."
    },
    {
      "scenario": "The driver's app loses connectivity mid-delivery in Indonesia",
      "expected_behavior": "Earnings are calculated server-side upon delivery completion. Real-time display resumes when connectivity is restored. No earnings are computed or displayed client-side to prevent tampering or inconsistency."
    }
  ],

  "business_impact": {
    "financial": "In California, non-compliance with Labor Code §226 carries penalties of $50 for the first violation and $100 per subsequent violation per employee per pay period, plus actual damages and attorney fees. Class action exposure for systematic violations could reach millions. In Germany, deploying without works council approval can result in injunctions and fines. Conversely, proper transparency reduces pay disputes and support costs.",
    "operational": "Requires jurisdiction-aware feature flagging, per-market compliance configuration, and integration with works council approval workflows. The Germany market cannot launch on the same timeline as others — it has a legal gate. The operations team needs a works council approval tracking process. The compensation team needs minimum wage violation alerting.",
    "user": "Drivers gain trust and satisfaction through transparent pay. Reduces support ticket volume for 'where did my money go?' queries. In California, drivers see legally mandated information they're entitled to. In Indonesia, transparency is a competitive differentiator for driver recruitment even though not legally required.",
    "risk": "HIGH for California — getting this wrong creates documented evidence of wage violations. MEDIUM for Germany — deploying prematurely violates co-determination rights. LOW for Indonesia on compliance, but reputational risk if the breakdown reveals unfavorable pay structures. CROSS-CUTTING: displaying real-time earnings creates a permanent auditable record that regulators and plaintiff attorneys can subpoena.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Receive legally mandated wage transparency; minimum wage violations are surfaced; high trust benefit" },
      { "group": "Drivers (Germany)", "impact": "Feature delayed until works council approves; must not feel excluded or disadvantaged during the wait" },
      { "group": "Drivers (Indonesia)", "impact": "Voluntary transparency improves trust and retention; no legal obligation but sets market expectation" },
      { "group": "Works Council (Germany)", "impact": "Must be consulted and must formally approve before any rollout; ongoing co-determination rights over changes to the feature" },
      { "group": "Legal / Compliance Team", "impact": "Must validate per-jurisdiction field requirements, deduction legality, and minimum wage thresholds; ongoing regulatory monitoring burden" },
      { "group": "Compensation / Payroll Team", "impact": "Receives minimum wage violation alerts; must have process to review and adjust; deduction catalog must be maintained" },
      { "group": "Product / Engineering", "impact": "Must build jurisdiction-aware feature with configurable compliance rules; cannot do a single global rollout" },
      { "group": "Platform (corporate)", "impact": "Creates a permanent auditable record of every pay calculation — beneficial for compliance but also discoverable in litigation" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The feature spec is high-level ('show earnings breakdown in real time') but the legal and regulatory implications are deep and jurisdiction-specific. Several critical details are unspecified: (1) no legal review has confirmed the exact §226 field requirements for a digital real-time display vs. traditional pay stubs, (2) the Germany works council process timeline and approval criteria are undefined, (3) driver classification is stated but not confirmed by local legal counsel, (4) it is unclear whether Indonesian contractor deductions have any disclosure requirements under local law. The multi-jurisdiction nature means errors in any market create independent legal exposure.",
    "high_confidence_areas": [
      "Tips must not subsidize base pay (well-established law and industry norm)",
      "Germany works council approval is required before rollout (clear BetrVG requirement)",
      "California drivers are employees under AB5 requiring minimum wage and itemized statements",
      "Earnings data must be private per driver",
      "Deductions must be individually itemized for transparency"
    ],
    "low_confidence_areas": [
      "Exact California §226 field requirements for a real-time digital display vs. traditional pay stub format",
      "Whether Indonesia has ANY deduction disclosure requirements for independent contractors",
      "Whether real-time display constitutes a 'wage statement' under California law or is supplementary to the formal pay stub",
      "Works council negotiation scope — they may demand changes beyond what we've specified",
      "Cross-border delivery jurisdiction resolution rules — no clear policy defined"
    ],
    "assumptions": [
      "California drivers are correctly classified as employees under AB5 — this has been validated by legal counsel",
      "The platform already has jurisdiction data per driver and per delivery",
      "Tips are collected and tracked separately from platform-funded compensation",
      "The works council approval process is binary (approved/not approved) — actual negotiation may impose additional conditions",
      "The real-time earnings display is supplementary to, not a replacement for, formal wage statements in California"
    ]
  },

  "escalations": [
    {
      "type": "missing_context",
      "description": "It is unclear whether this real-time earnings display legally constitutes an 'itemized wage statement' under California Labor Code §226, or whether it is supplementary to a separate formal pay stub. If it IS the wage statement, the legal field requirements are mandatory and non-negotiable. If supplementary, some fields may be optional in this view. This distinction fundamentally changes the required data model for California.",
      "affected_stakeholders": ["Legal / Compliance Team", "Drivers (California)", "Product / Engineering"],
      "options": [
        "A: Treat the feature AS the itemized wage statement — include all §226 fields, accept the overhead",
        "B: Treat the feature as supplementary — show the four requested components plus a link to the formal pay stub",
        "C: Build both — real-time simplified view plus a compliant formal statement accessible from within the feature"
      ],
      "recommendation": "Option C — build the real-time view with all four components for immediate transparency, PLUS ensure a fully §226-compliant formal statement is accessible. This satisfies both the product goal and the legal requirement without ambiguity. But this MUST be confirmed by legal counsel before implementation."
    },
    {
      "type": "missing_context",
      "description": "No information provided about Indonesian labor law requirements for independent contractor payment disclosure. While the spec says 'local law does not require pay transparency,' we have not confirmed whether there are ANY requirements around deduction disclosure, payment timing, or receipt obligations for contractors in Indonesia.",
      "affected_stakeholders": ["Legal / Compliance Team", "Drivers (Indonesia)"],
      "options": [
        "A: Proceed with the four-component breakdown with no additional Indonesian-specific fields",
        "B: Engage local Indonesian legal counsel to confirm zero disclosure obligations before building"
      ],
      "recommendation": "Option B — engage local counsel to confirm. The cost of a legal review is trivial compared to the cost of a compliance violation discovered post-launch. Do not assume 'no transparency law' means 'no obligations.'"
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define what real-time means operationally. Does it mean per-delivery instant visibility? Per-shift running totals? Per-day? The answer affects architecture, data freshness SLAs, and user expectations. I have assumed per-delivery within 60 seconds, but this needs product confirmation.",
      "affected_stakeholders": ["Product / Engineering", "Drivers (all jurisdictions)"],
      "options": [
        "A: Per-delivery real-time (within 60s of delivery completion)",
        "B: Running shift total updated after each delivery",
        "C: Both — per-delivery detail plus running totals"
      ],
      "recommendation": "Option C — drivers need both the per-delivery breakdown and a running total for the day/shift. But the SLA definition must come from product."
    }
  ],

  "rejection_reasons": []
}

